 82→/**
 83→ * Project a 3D point onto a plane, returning local (u, v) coordinates.
 84→ */
 85→export function projectToPlane(point3d, plane) {
 86→  const dx = point3d.x - plane.origin.x;
 87→  const dy = point3d.y - plane.origin.y;
 88→  const dz = point3d.z - plane.origin.z;
 89→  const u = dx * plane.uAxis.x + dy * plane.uAxis.y + dz * plane.uAxis.z;
 90→  const v = dx * plane.vAxis.x + dy * plane.vAxis.y + dz * plane.vAxis.z;
 91→  return { u, v };
 92→}
 93→
 94→/**
 95→ * Convert local (u, v) on a plane back to 3D world coordinates.
 96→ */
 97→export function planeLocalToWorld(u, v, plane) {
 98→  return {
 99→    x: plane.origin.x + u * plane.uAxis.x + v * plane.vAxis.x,
100→    y: plane.origin.y + u * plane.uAxis.y + v * plane.vAxis.y,
101→    z: plane.origin.z + u * plane.uAxis.z + v * plane.vAxis.z,
102→  };
103→}
104→
105→/**
106→ * Map a Three.js face normal (approximate) to a canonical face ID.
107→ * Three.js coords: x=domain x, y=domain z, z=domain y
108→ */
109→export function identifyFace(threeNormal) {
110→  const ax = Math.abs(threeNormal.x);
111→  const ay = Math.abs(threeNormal.y);
112→  const az = Math.abs(threeNormal.z);
113→
114→  if (ay >= ax && ay >= az) {
115→    return threeNormal.y > 0 ? '+z' : '-z'; // Three.js Y = domain Z
116→  }
117→  if (ax >= ay && ax >= az) {
118→    return threeNormal.x > 0 ? '+x' : '-x';
119→  }
120→  return threeNormal.z > 0 ? '+y' : '-y'; // Three.js Z = domain Y
121→}
122→
123→/**
124→ * Get uniform dimensions for any part type.
125→ */
126→function getPartDimensions(part) {
127→  switch (part.type) {
128→    case 'panel':
129→      return { width: part.width, depth: part.depth, height: part.thickness };
130→    case 'leg':
131→      return { width: part.width, depth: part.depth, height: part.height };
132→    case 'frame': {
133→      const w = part.axis === 'y' ? part.width : part.length;
134→      const d = part.axis === 'y' ? part.length : part.width;
135→      return { width: w, depth: d, height: part.height };
136→    }
137→    default:
138→      return { width: part.width || 100, depth: part.depth || 100, height: part.height || part.thickness || 18 };
139→  }
140→}
