 31→
 32→  const ctx = {
 33→    dispatch: sketchDispatch,
 34→    editorDispatch,
 35→    project,
 36→    activeView,
 37→    activeAssemblyId,
 38→    viewport,
 39→    snapEnabled,
 40→    selectedId,
 41→    selectedType,
 42→  };
 43→
 44→  switch (activeTool) {
 45→    case 'panel':
