174→function SketchInner() {
175→  const { project, isDirty, dispatch } = useSketch();
176→  const { workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
177→  const [showLoadModal, setShowLoadModal] = useState(false);
178→  const [showTemplateDialog, setShowTemplateDialog] = useState(false);
179→  const [fileHandle, setFileHandle] = useState(null);
180→
181→  // Autosave
182→  useSketchAutosave(project, isDirty, dispatch);
183→
184→  // beforeunload warning
185→  useEffect(() => {
186→    const handler = (e) => {
187→      if (isDirty) {
188→        e.preventDefault();
189→        e.returnValue = '';
190→      }
191→    };
192→    window.addEventListener('beforeunload', handler);
193→    return () => window.removeEventListener('beforeunload', handler);
194→  }, [isDirty]);
195→
196→  // Ctrl+S file save
197→  useEffect(() => {
198→    const handler = async (e) => {
199→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
200→        e.preventDefault();
201→        try {
202→          const result = await exportSketchProjectFile(project, { fileHandle });
203→          if (result.fileHandle) setFileHandle(result.fileHandle);
204→          await saveSketchProject(project);
205→          dispatch({ type: 'MARK_SAVED' });
206→        } catch (err) {
207→          if (!isFilePickerAbortError(err)) {
208→            console.error('Save failed:', err);
209→          }
210→        }
211→      }
212→    };
213→    window.addEventListener('keydown', handler);
214→    return () => window.removeEventListener('keydown', handler);
215→  }, [project, fileHandle, dispatch]);
216→
217→  // If active sheet was deleted, revert to model mode
218→  useEffect(() => {
219→    if (workspaceMode === 'sheet' && activeSheetId) {
220→      const sheetExists = (project.sheets || []).some((s) => s.id === activeSheetId);
221→      if (!sheetExists) {
222→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
223→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
224→      }
225→    }
226→  }, [workspaceMode, activeSheetId, project.sheets, editorDispatch]);
227→
228→  const handleNew = useCallback(() => {
229→    if (isDirty && !window.confirm('You have unsaved changes. Start a new project?')) return;
230→    dispatch({ type: 'SKETCH_NEW' });
231→    setFileHandle(null);
232→  }, [isDirty, dispatch]);
233→
234→  const handleSave = useCallback(async () => {
235→    try {
236→      const result = await exportSketchProjectFile(project, { fileHandle });
237→      if (result.fileHandle) setFileHandle(result.fileHandle);
238→      await saveSketchProject(project);
239→      dispatch({ type: 'MARK_SAVED' });
240→    } catch (err) {
241→      if (!isFilePickerAbortError(err)) {
242→        console.error('Save failed:', err);
243→      }
244→    }
245→  }, [project, fileHandle, dispatch]);
246→
247→  const handleLoadClick = useCallback(() => {
248→    setShowLoadModal(true);
249→  }, []);
250→
251→  const isSheetMode = workspaceMode === 'sheet';
252→
253→  return (
254→    <SketchProjectContext.Provider value={{ handleNew, handleSave, handleLoadClick, fileHandle, setFileHandle, showTemplateDialog, setShowTemplateDialog }}>
255→      <div className={styles.layout}>
256→        <div className={styles.toolbar}>
257→          <SketchToolbar />
258→        </div>
259→        <div className={styles.sidebar}>
260→          <SketchSidebar />
261→        </div>
262→        <div className={styles.canvas}>
263→          {isSheetMode ? (
264→            <Suspense fallback={<div className={styles.previewFallback}>Loading sheet...</div>}>
265→              <SketchSheetCanvas />
266→            </Suspense>
267→          ) : (
268→            <SketchViewport />
269→          )}
270→        </div>
271→        <div className={styles.rightPanel}>
272→          <SketchPropertiesPanel />
273→        </div>
274→      </div>
275→      {showLoadModal && <SketchLoadModal onClose={() => setShowLoadModal(false)} />}
276→      {showTemplateDialog && (
277→        <TemplateDialog
278→          onClose={() => setShowTemplateDialog(false)}
279→          onGenerate={(templateType, params) => {
280→            const objectId = generateId('obj');
281→            dispatch({ type: 'TEMPLATE_GENERATE', templateType, params, objectId });
282→            editorDispatch({ type: 'DISMISS_EMPTY_STATE' });
283→            editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
284→            editorDispatch({ type: 'SELECT_OBJECT', id: objectId, objectType: 'object' });
285→          }}
286→        />
287→      )}
288→    </SketchProjectContext.Provider>
289→  );
290→}
