261→    const threePlane = domainPlaneToThreePlane(plane);
262→    const drawingPlanePoint3 = new THREE.Vector3();
263→    const hasPlaneHit = raycaster.ray.intersectPlane(threePlane, drawingPlanePoint3);
264→    const drawingPlanePoint = hasPlaneHit
265→      ? { x: drawingPlanePoint3.x, y: drawingPlanePoint3.z, z: drawingPlanePoint3.y } // Three.js -> domain
266→      : null;
