 * @param {Object} part
 * @returns {Array<{x: number, y: number, z: number}>}
 */
export function getPartCorners(part) {
  const { position } = part;
  const dims = getPartDimensions(part);
  const x0 = position.x;
  const y0 = position.y;
  const z0 = position.z;
  const x1 = x0 + dims.width;
  const y1 = y0 + dims.depth;
  const z1 = z0 + dims.height;

