    { x: x0, y: y0, z: z0 },
    { x: x1, y: y0, z: z0 },
    { x: x0, y: y1, z: z0 },
    { x: x1, y: y1, z: z0 },
    { x: x0, y: y0, z: z1 },
    { x: x1, y: y0, z: z1 },
    { x: x0, y: y1, z: z1 },
    { x: x1, y: y1, z: z1 },
