export function getPartEdgeMidpoints(part) {
  const { position } = part;
  const dims = getPartDimensions(part);
  const x0 = position.x;
  const y0 = position.y;
  const z0 = position.z;
  const x1 = x0 + dims.width;
  const y1 = y0 + dims.depth;
  const z1 = z0 + dims.height;
  const mx = (x0 + x1) / 2;
  const my = (y0 + y1) / 2;
  const mz = (z0 + z1) / 2;

  return [
    // Bottom face edges (z=z0)
    { x: mx, y: y0, z: z0 },
    { x: mx, y: y1, z: z0 },
    { x: x0, y: my, z: z0 },
    { x: x1, y: my, z: z0 },
    // Top face edges (z=z1)
    { x: mx, y: y0, z: z1 },
    { x: mx, y: y1, z: z1 },
    { x: x0, y: my, z: z1 },
    { x: x1, y: my, z: z1 },
