  switch (activeTool) {
    case 'panel':
    case 'leg':
    case 'frame':
      return createDrawRectHandler3d({ ...ctx, partType: activeTool, drawingPlane });

    case 'pushpull':
      return createPushPullHandler3d(ctx);

    case 'select':
    default:
      return createSelectHandler3d(ctx);
