      vAxis = { x: 0, y: 0, z: 1 };
      up = { x: 0, y: 0, z: 1 };
      break;
    case '-x': // left face
      origin = { x: position.x, y: position.y, z: position.z };
      normal = { x: -1, y: 0, z: 0 };
      uAxis = { x: 0, y: 1, z: 0 };
      vAxis = { x: 0, y: 0, z: 1 };
      up = { x: 0, y: 0, z: 1 };
      break;
    case '+y': // back face
      origin = { x: position.x, y: position.y + dims.depth, z: position.z };
      normal = { x: 0, y: 1, z: 0 };
      uAxis = { x: 1, y: 0, z: 0 };
      vAxis = { x: 0, y: 0, z: 1 };
      up = { x: 0, y: 0, z: 1 };
      break;
    case '-y': // front face
      origin = { x: position.x, y: position.y, z: position.z };
      normal = { x: 0, y: -1, z: 0 };
      uAxis = { x: 1, y: 0, z: 0 };
      vAxis = { x: 0, y: 0, z: 1 };
      up = { x: 0, y: 0, z: 1 };
